+import { neon } from "@neondatabase/serverless";
+
+const LEVEL = 3;
+const MAX_LIMIT = 25;
+const DEFAULT_LIMIT = 10;
+const OUTCOMES = new Set(["win", "loss"]);
+const TYPES = new Set(["winners", "attempts", "recent"]);
+
+let sqlClient;
+let schemaReady;
+
+function getConnectionString() {
+  return process.env.DATABASE_URL || process.env.POSTGRES_URL || "";
+}
+
+function getSql() {
+  if (!sqlClient) {
+    const connectionString = getConnectionString();
+    if (!connectionString) {
+      const err = new Error("Database connection is not configured");
+      err.statusCode = 503;
+      throw err;
+    }
+    sqlClient = neon(connectionString);
+  }
+  return sqlClient;
+}
+
+async function ensureSchema() {
+  if (!schemaReady) {
+    const sql = getSql();
+    schemaReady = (async () => {
+      await sql`
+        CREATE TABLE IF NOT EXISTS leaderboard_entries (
+          id uuid PRIMARY KEY,
+          username text NOT NULL CHECK (char_length(username) BETWEEN 2 AND 18),
+          level integer NOT NULL DEFAULT 3 CHECK (level = 3),
+          outcome text NOT NULL CHECK (outcome IN ('win', 'loss')),
+          score integer NOT NULL CHECK (score >= 0),
+          time_remaining integer NOT NULL DEFAULT 0 CHECK (time_remaining >= 0),
+          duration_seconds integer NOT NULL DEFAULT 0 CHECK (duration_seconds >= 0),
+          questions_completed integer NOT NULL DEFAULT 0 CHECK (questions_completed >= 0),
+          created_at timestamptz NOT NULL DEFAULT now()
+        )
+      `;
+      await sql`
+        CREATE INDEX IF NOT EXISTS leaderboard_entries_score_idx
+        ON leaderboard_entries (level, score DESC, time_remaining DESC, duration_seconds ASC, created_at ASC)
+      `;
+      await sql`
+        CREATE INDEX IF NOT EXISTS leaderboard_entries_recent_idx
+        ON leaderboard_entries (level, created_at DESC)
+      `;
+    })();
+  }
+  return schemaReady;
+}
+
+function sendJson(res, status, body) {
+  res.statusCode = status;
+  res.setHeader("Content-Type", "application/json; charset=utf-8");
+  res.setHeader("Cache-Control", "no-store");
+  res.end(JSON.stringify(body));
+}
+
+function normalizeUsername(value) {
+  return String(value || "")
+    .trim()
+    .replace(/\s+/g, " ")
+    .slice(0, 18);
+}
+
+function readInteger(value, fallback = 0) {
+  const n = Number(value);
+  if (!Number.isFinite(n)) return fallback;
+  return Math.max(0, Math.round(n));
+}
+
+function readLimit(value) {
+  const n = readInteger(value, DEFAULT_LIMIT);
+  return Math.min(MAX_LIMIT, Math.max(1, n || DEFAULT_LIMIT));
