+const API_PATH = "/api/leaderboard";
+const STORAGE_KEY = "planetfall:leaderboard:v1";
+const MAX_LOCAL_ENTRIES = 50;
+
+function clampInt(value, fallback = 0) {
+  const n = Number(value);
+  if (!Number.isFinite(n)) return fallback;
+  return Math.max(0, Math.round(n));
+}
+
+function normalizeEntry(entry) {
+  return {
+    id: entry.id || crypto.randomUUID(),
+    username: String(entry.username || "PILOT").trim().slice(0, 18),
+    level: 3,
+    outcome: entry.outcome === "win" ? "win" : "loss",
+    score: clampInt(entry.score),
+    timeRemaining: clampInt(entry.timeRemaining),
+    durationSeconds: clampInt(entry.durationSeconds),
+    questionsCompleted: Math.min(3, clampInt(entry.questionsCompleted)),
+    createdAt: entry.createdAt || new Date().toISOString(),
+  };
+}
+
+function getLocalEntries() {
+  try {
+    const raw = localStorage.getItem(STORAGE_KEY);
+    const entries = raw ? JSON.parse(raw) : [];
+    return Array.isArray(entries) ? entries.map(normalizeEntry) : [];
+  } catch {
+    return [];
+  }
+}
+
+function setLocalEntries(entries) {
+  try {
+    localStorage.setItem(STORAGE_KEY, JSON.stringify(entries.slice(0, MAX_LOCAL_ENTRIES)));
+  } catch {
+    // Private browsing/storage limits should not break the end screen.
+  }
+}
+
+function sortEntries(entries, type) {
+  const source = type === "winners"
+    ? entries.filter((entry) => entry.outcome === "win")
+    : [...entries];
+
+  if (type === "recent") {
+    return source.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
+  }
+
+  return source.sort((a, b) =>
+    b.score - a.score ||
+    b.timeRemaining - a.timeRemaining ||
+    a.durationSeconds - b.durationSeconds ||
+    new Date(a.createdAt) - new Date(b.createdAt)
+  );
+}
+
+async function requestJson(path, options) {
+  const res = await fetch(path, {
+    headers: { "Content-Type": "application/json" },
+    ...options,
+  });
+  const payload = await res.json().catch(() => ({}));
+  if (!res.ok) {
+    const err = new Error(payload.error || "Leaderboard request failed");
+    err.status = res.status;
+    throw err;
+  }
+  return payload;
+}
+
+export function createLeaderboardEntry({ outcome, totalTime, timeLeft, questionsCompleted, mistakes }) {
+  const remaining = outcome === "win" ? clampInt(timeLeft) : 0;
+  const completed = Math.min(3, clampInt(questionsCompleted));
+  const missPenalty = clampInt(mistakes) * 500;
+  const clearBonus = outcome === "win" ? 50000 : 0;
+  const score = Math.max(0, clearBonus + completed * 10000 + remaining * 100 - missPenalty);
+
+  return {
+    level: 3,
+    outcome,
+    score,
+    timeRemaining: remaining,
+    durationSeconds: Math.max(0, clampInt(totalTime) - remaining),
+    questionsCompleted: completed,
+  };
+}
+
+export async function loadLeaderboard(type = "winners") {
+  try {
+    const payload = await requestJson(`${API_PATH}?type=${encodeURIComponent(type)}&limit=10`);
+    return { entries: payload.entries.map(normalizeEntry), source: payload.source || "database" };
+  } catch {
+    return { entries: sortEntries(getLocalEntries(), type).slice(0, 10), source: "local" };
+  }
+}
+
+export async function saveLeaderboardEntry(entry) {
+  const normalized = normalizeEntry(entry);
+
+  try {
+    const payload = await requestJson(API_PATH, {
+      method: "POST",
+      body: JSON.stringify(normalized),
+    });
+    return {
+      entry: normalizeEntry(payload.entry),
+      entries: payload.entries.map(normalizeEntry),
+      source: payload.source || "database",
+    };
+  } catch {
+    const entries = [normalized, ...getLocalEntries()];
+    const sorted = sortEntries(entries, normalized.outcome === "win" ? "winners" : "attempts");
+    setLocalEntries(sortEntries(entries, "attempts"));
+    return { entry: normalized, entries: sorted.slice(0, 10), source: "local" };
+  }
+}
