import { neon } from "@neondatabase/serverless";

const LEVEL = 3;
const MAX_LIMIT = 25;
const DEFAULT_LIMIT = 10;
const OUTCOMES = new Set(["win", "loss"]);
const TYPES = new Set(["winners", "attempts", "recent"]);

let sqlClient;
let schemaReady;

function getConnectionString() {
  return process.env.DATABASE_URL || process.env.POSTGRES_URL || "";
}

function getSql() {
  if (!sqlClient) {
    const connectionString = getConnectionString();
    if (!connectionString) {
      const err = new Error("Database connection is not configured");
      err.statusCode = 503;
      throw err;
    }
    sqlClient = neon(connectionString);
  }
  return sqlClient;
}

async function ensureSchema() {
  if (!schemaReady) {
    const sql = getSql();
    schemaReady = (async () => {
      await sql`
        CREATE TABLE IF NOT EXISTS leaderboard_entries (
          id uuid PRIMARY KEY,
          username text NOT NULL CHECK (char_length(username) BETWEEN 2 AND 18),
          level integer NOT NULL DEFAULT 3 CHECK (level = 3),
          outcome text NOT NULL CHECK (outcome IN ('win', 'loss')),
          score integer NOT NULL CHECK (score >= 0),
          time_remaining integer NOT NULL DEFAULT 0 CHECK (time_remaining >= 0),
          duration_seconds integer NOT NULL DEFAULT 0 CHECK (duration_seconds >= 0),
          questions_completed integer NOT NULL DEFAULT 0 CHECK (questions_completed >= 0),
          created_at timestamptz NOT NULL DEFAULT now()
        )
      `;
      await sql`
        CREATE INDEX IF NOT EXISTS leaderboard_entries_score_idx
        ON leaderboard_entries (level, score DESC, time_remaining DESC, duration_seconds ASC, created_at ASC)
      `;
      await sql`
        CREATE INDEX IF NOT EXISTS leaderboard_entries_recent_idx
        ON leaderboard_entries (level, created_at DESC)
      `;
    })();
  }
  return schemaReady;
}

function sendJson(res, status, body) {
  res.statusCode = status;
  res.setHeader("Content-Type", "application/json; charset=utf-8");
  res.setHeader("Cache-Control", "no-store");
  res.end(JSON.stringify(body));
}

function normalizeUsername(value) {
  return String(value || "")
    .trim()
    .replace(/\s+/g, " ")
    .slice(0, 18);
}

function readInteger(value, fallback = 0) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(0, Math.round(n));
}

function readLimit(value) {
  const n = readInteger(value, DEFAULT_LIMIT);
  return Math.min(MAX_LIMIT, Math.max(1, n || DEFAULT_LIMIT));
}

function validateEntry(body) {
  const username = normalizeUsername(body.username);
  if (!/^[a-zA-Z0-9 ._-]{2,18}$/.test(username)) {
    const err = new Error("Callsign must be 2-18 letters, numbers, spaces, dots, dashes, or underscores");
    err.statusCode = 400;
    throw err;
  }

  const outcome = String(body.outcome || "").toLowerCase();
  if (!OUTCOMES.has(outcome)) {
    const err = new Error("Outcome must be win or loss");
    err.statusCode = 400;
    throw err;
  }

  const level = readInteger(body.level, LEVEL);
  if (level !== LEVEL) {
    const err = new Error("Only Level 3 leaderboard entries are accepted");
    err.statusCode = 400;
    throw err;
  }

  return {
    id: crypto.randomUUID(),
    username,
    level,
    outcome,
    score: readInteger(body.score),
    timeRemaining: readInteger(body.timeRemaining),
    durationSeconds: readInteger(body.durationSeconds),
    questionsCompleted: Math.min(3, readInteger(body.questionsCompleted)),
  };
}

async function listEntries(sql, type, limit) {
  if (type === "recent") {
    return sql`
      SELECT
        id,
        username,
        level,
        outcome,
        score,
        time_remaining AS "timeRemaining",
        duration_seconds AS "durationSeconds",
        questions_completed AS "questionsCompleted",
        created_at AS "createdAt"
      FROM leaderboard_entries
      WHERE level = ${LEVEL}
      ORDER BY created_at DESC
      LIMIT ${limit}
    `;
  }

  if (type === "winners") {
    return sql`
      SELECT
        id,
        username,
        level,
        outcome,
        score,
        time_remaining AS "timeRemaining",
        duration_seconds AS "durationSeconds",
        questions_completed AS "questionsCompleted",
        created_at AS "createdAt"
      FROM leaderboard_entries
      WHERE level = ${LEVEL} AND outcome = 'win'
      ORDER BY score DESC, time_remaining DESC, duration_seconds ASC, created_at ASC
      LIMIT ${limit}
    `;
  }

  return sql`
    SELECT
      id,
      username,
      level,
      outcome,
      score,
      time_remaining AS "timeRemaining",
      duration_seconds AS "durationSeconds",
      questions_completed AS "questionsCompleted",
      created_at AS "createdAt"
    FROM leaderboard_entries
    WHERE level = ${LEVEL}
    ORDER BY score DESC, time_remaining DESC, duration_seconds ASC, created_at ASC
    LIMIT ${limit}
  `;
}

export default async function handler(req, res) {
  if (req.method === "OPTIONS") {
    res.statusCode = 204;
    res.end();
    return;
  }

  try {
    await ensureSchema();
    const sql = getSql();

    if (req.method === "GET") {
      const type = TYPES.has(req.query.type) ? req.query.type : "winners";
      const limit = readLimit(req.query.limit);
      const entries = await listEntries(sql, type, limit);
      sendJson(res, 200, { entries, source: "database" });
      return;
    }

    if (req.method === "POST") {
      const entry = validateEntry(req.body || {});
      const inserted = await sql`
        INSERT INTO leaderboard_entries (
          id,
          username,
          level,
          outcome,
          score,
          time_remaining,
          duration_seconds,
          questions_completed
        )
        VALUES (
          ${entry.id},
          ${entry.username},
          ${entry.level},
          ${entry.outcome},
          ${entry.score},
          ${entry.timeRemaining},
          ${entry.durationSeconds},
          ${entry.questionsCompleted}
        )
        RETURNING
          id,
          username,
          level,
          outcome,
          score,
          time_remaining AS "timeRemaining",
          duration_seconds AS "durationSeconds",
          questions_completed AS "questionsCompleted",
          created_at AS "createdAt"
      `;
      const entries = await listEntries(sql, entry.outcome === "win" ? "winners" : "attempts", DEFAULT_LIMIT);
      sendJson(res, 201, { entry: inserted[0], entries, source: "database" });
      return;
    }

    res.setHeader("Allow", "GET, POST, OPTIONS");
    sendJson(res, 405, { error: "Method not allowed" });
  } catch (error) {
    const status = error.statusCode || 500;
    const message = status === 500 ? "Leaderboard is unavailable" : error.message;
    console.error("leaderboard api error", error);
    sendJson(res, status, { error: message });
  }
}

const API_PATH = "/api/leaderboard";
const STORAGE_KEY = "planetfall:leaderboard:v1";
const MAX_LOCAL_ENTRIES = 50;

function clampInt(value, fallback = 0) {
  const n = Number(value);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(0, Math.round(n));
}

function normalizeEntry(entry) {
  return {
    id: entry.id || crypto.randomUUID(),
    username: String(entry.username || "PILOT").trim().slice(0, 18),
    level: 3,
    outcome: entry.outcome === "win" ? "win" : "loss",
    score: clampInt(entry.score),
    timeRemaining: clampInt(entry.timeRemaining),
    durationSeconds: clampInt(entry.durationSeconds),
    questionsCompleted: Math.min(3, clampInt(entry.questionsCompleted)),
    createdAt: entry.createdAt || new Date().toISOString(),
  };
}

function getLocalEntries() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    const entries = raw ? JSON.parse(raw) : [];
    return Array.isArray(entries) ? entries.map(normalizeEntry) : [];
  } catch {
    return [];
  }
}

function setLocalEntries(entries) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(entries.slice(0, MAX_LOCAL_ENTRIES)));
  } catch {
    // Private browsing/storage limits should not break the end screen.
  }
}

function sortEntries(entries, type) {
  const source = type === "winners"
    ? entries.filter((entry) => entry.outcome === "win")
    : [...entries];

  if (type === "recent") {
    return source.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  }

  return source.sort((a, b) =>
    b.score - a.score ||
    b.timeRemaining - a.timeRemaining ||
    a.durationSeconds - b.durationSeconds ||
    new Date(a.createdAt) - new Date(b.createdAt)
  );
}

async function requestJson(path, options) {
  const res = await fetch(path, {
    headers: { "Content-Type": "application/json" },
    ...options,
  });
  const payload = await res.json().catch(() => ({}));
  if (!res.ok) {
    const err = new Error(payload.error || "Leaderboard request failed");
    err.status = res.status;
    throw err;
  }
  return payload;
}

export function createLeaderboardEntry({ outcome, totalTime, timeLeft, questionsCompleted, mistakes }) {
  const remaining = outcome === "win" ? clampInt(timeLeft) : 0;
  const completed = Math.min(3, clampInt(questionsCompleted));
  const missPenalty = clampInt(mistakes) * 500;
  const clearBonus = outcome === "win" ? 50000 : 0;
  const score = Math.max(0, clearBonus + completed * 10000 + remaining * 100 - missPenalty);

  return {
    level: 3,
    outcome,
    score,
    timeRemaining: remaining,
    durationSeconds: Math.max(0, clampInt(totalTime) - remaining),
    questionsCompleted: completed,
  };
}

export async function loadLeaderboard(type = "winners") {
  try {
    const payload = await requestJson(`${API_PATH}?type=${encodeURIComponent(type)}&limit=10`);
    return { entries: payload.entries.map(normalizeEntry), source: payload.source || "database" };
  } catch {
    return { entries: sortEntries(getLocalEntries(), type).slice(0, 10), source: "local" };
  }
}

export async function saveLeaderboardEntry(entry) {
  const normalized = normalizeEntry(entry);

  try {
    const payload = await requestJson(API_PATH, {
      method: "POST",
      body: JSON.stringify(normalized),
    });
    return {
      entry: normalizeEntry(payload.entry),
      entries: payload.entries.map(normalizeEntry),
      source: payload.source || "database",
    };
  } catch {
    const entries = [normalized, ...getLocalEntries()];
    const sorted = sortEntries(entries, normalized.outcome === "win" ? "winners" : "attempts");
    setLocalEntries(sortEntries(entries, "attempts"));
    return { entry: normalized, entries: sorted.slice(0, 10), source: "local" };
  }
}

